import React, { useState } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { analyzeImage } from "./api";
import { ClipLoader } from "react-spinners";

function UploadImage() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [age, setAge] = useState("");
  const [sex, setSex] = useState("");

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    if (!selectedFile.type.startsWith("image/")) {
      setError("Please upload an image file (JPEG, PNG)");
      return;
    }

    setFile(selectedFile);
    setError("");
    setReport("");
  };

  const handleUpload = async () => {
    if (!file) {
      setError("Please select an image file");
      return;
    }

    if (!age || !sex) {
      setError("Please provide patient age and sex");
      return;
    }

    setLoading(true);
    setError("");
    setReport("");

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("age", age);
      formData.append("sex", sex);

      const data = await analyzeImage(formData);

      if (data?.analysis) {
        setReport(data.analysis);
      } else {
        setError(data?.detail || "Failed to analyze image");
      }
    } catch (err) {
      console.error("Analysis error:", err);
      setError(err.message || "Image analysis failed");
    } finally {
      setLoading(false);
    }
  };

  const MarkdownComponents = {
    strong({ node, children }) {
      const textContent = React.Children.toArray(children)
        .map(child => typeof child === 'string' ? child : '')
        .join('');

      const match = textContent.match(/(.*?)\s*\((certainty:\s*\d+%)\)/i);

      if (match) {
        return (
          <span className="font-semibold">
            {match[1]}{" "}
            <span className="text-blue-600 dark:text-blue-400">
              ({match[2]})
            </span>
          </span>
        );
      }
      return <strong>{children}</strong>;
    },
    ul: ({ node, children }) => (
      <ul className="list-disc pl-6 mb-4 space-y-2">{children}</ul>
    ),
    li: ({ node, children }) => (
      <li className="marker:text-gray-500 dark:marker:text-gray-400">
        {children}
      </li>
    ),
    p: ({ node, children }) => (
      <p className="mb-4 leading-relaxed text-gray-700 dark:text-gray-300">
        {children}
      </p>
    ),
    h3: ({ node, children }) => (
      <h3 className="text-lg font-semibold mt-6 mb-3 text-gray-800 dark:text-gray-100">
        {children}
      </h3>
    )
  };

  return (
    <div className="p-6 bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl mx-auto">
      <h2 className="text-2xl font-bold mb-6 text-gray-800 dark:text-gray-100">
        Medical Imaging Analysis Platform
      </h2>

      <div className="space-y-5">
        {/* File Upload Section */}
        <div className="space-y-2">
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
            Upload Medical Image
          </label>
          <input
            type="file"
            onChange={handleFileChange}
            accept="image/*"
            className="block w-full text-sm text-gray-500
              file:mr-4 file:py-2.5 file:px-4
              file:rounded-lg file:border-0
              file:text-sm file:font-semibold
              file:bg-blue-600 file:text-white
              hover:file:bg-blue-700 transition-colors
              cursor-pointer disabled:cursor-not-allowed"
          />
        </div>

        {/* Patient Information */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
              Patient Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/[^0-9]/g, ''))}
              min="0"
              max="120"
              className="w-full p-2.5 border rounded-lg
                dark:bg-gray-700 dark:border-gray-600
                focus:ring-2 focus:ring-blue-500"
              placeholder="Enter age"
              required
            />
          </div>
          <div className="space-y-1">
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
              Biological Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-2.5 border rounded-lg
                dark:bg-gray-700 dark:border-gray-600
                focus:ring-2 focus:ring-blue-500"
              required
            >
              <option value="">Select sex</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analysis Button */}
        <button
          onClick={handleUpload}
          disabled={loading || !file}
          className={`w-full py-3.5 px-6 rounded-lg font-semibold text-white
            transition-colors duration-200 ${loading || !file 
              ? 'bg-gray-400 cursor-not-allowed' 
              : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-2">
              <ClipLoader color="#ffffff" size={22} />
              <span>Analyzing Image...</span>
            </div>
          ) : (
            'Analyze Image'
          )}
        </button>

        {/* Error Display */}
        {error && (
          <div className="p-3.5 bg-red-100/80 dark:bg-red-900/50
            text-red-700 dark:text-red-200 rounded-lg
            border border-red-200 dark:border-red-800">
           ⚠️ {error}
          </div>
        )}

        {/* Analysis Results */}
        {report && !error && (
          <div className="mt-6 bg-gray-50/80 dark:bg-gray-700/90
            p-6 rounded-lg shadow-inner border
            border-gray-100 dark:border-gray-600">
            <h3 className="text-xl font-semibold mb-5 text-gray-800
              dark:text-gray-100 pb-2 border-b
              border-gray-200 dark:border-gray-600">
              AI Analysis Report
            </h3>
            <div className="prose dark:prose-invert max-w-none">
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                components={MarkdownComponents}
              >
                {report.replace(/\n{2,}/g, '\n\n')}
              </ReactMarkdown>
            </div>
            <div className="mt-6 p-3.5 bg-yellow-100/80 dark:bg-yellow-900/50
              rounded-lg border border-yellow-200 dark:border-yellow-800">
              <p className="text-sm text-yellow-800 dark:text-yellow-200
                leading-snug">
                ⚠️ Important: This AI-generated analysis requires clinical
                validation by a board-certified radiologist. Findings should
                be correlated with patient history and additional diagnostic
                tests as needed.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default UploadImage;
